from dataclasses import dataclass

@dataclass
class KPITile:
    label: str
    value: str
    delta_str: str      # e.g. "▼ 8% vs last month"
    status: str         # "OK" | "WARN" | "CRITICAL"

def format_kpi_tile(
    key: str,
    current: float,
    prior: Optional[float] = None,
) -> KPITile:
    spec = METRIC_BY_KEY[key]
    formatted = format(current, spec.format_str)
    if spec.unit == "pct":
        formatted += "%"

    delta_str = ""
    if prior is not None and prior != 0:
        delta_pct = (current - prior) / prior * 100
        arrow = "▼" if delta_pct < 0 else "▲"
        color_word = ""
        if spec.direction == "lower_better":
            color_word = "GOOD" if delta_pct < 0 else "BAD"
        else:
            color_word = "GOOD" if delta_pct > 0 else "BAD"
        delta_str = f"{arrow} {abs(delta_pct):.1f}% vs prior period [{color_word}]"

    return KPITile(
        label=spec.label,
        value=formatted,
        delta_str=delta_str,
        status=spec.status(current),
    )

def render_text_dashboard(
    feature: str,
    period: str,
    kpis: dict[str, float],
    prior_kpis: Optional[dict[str, float]] = None,
    trend: Optional[list[dict]] = None,
) -> str:
    lines = [
        f"=== Unit Economics: {feature} | {period} ===",
        "",
    ]
    for key in ["cost_per_conv", "llm_cost_ratio", "gross_margin_pct", "p95_cost_conv"]:
        if key not in kpis:
            continue
        tile = format_kpi_tile(key, kpis[key], (prior_kpis or {}).get(key))
        status_icon = {"OK": "✓", "WARN": "⚠", "CRITICAL": "✗"}.get(tile.status, "?")
        lines.append(f"  [{status_icon}] {tile.label:<30} {tile.value:>10}  {tile.delta_str}")
    if trend:
        lines += ["", "  Trend (cost/conv):"]
        for t in trend:
            bar = "█" * int(t["avg_cost"] / 0.005)
            lines.append(f"  {t['period']}  {bar:<20} ${t['avg_cost']:.4f}")
    return "\n".join(lines)

# Industry benchmarks for GenAI B2B SaaS (2024–2025 survey data)
