        "cost_per_conv_p90_usd":  0.35,
        "llm_cost_ratio_p50":     0.22,
        "gross_margin_p50_pct":   48.0,
        "resolution_rate_p50":    0.68,
    },
    "document_drafter": {
        "cost_per_conv_p50_usd":  0.08,
        "cost_per_conv_p90_usd":  0.28,
        "llm_cost_ratio_p50":     0.20,
        "gross_margin_p50_pct":   52.0,
        "resolution_rate_p50":    0.80,
    },
    "autonomous_agent": {
        "cost_per_conv_p50_usd":  0.30,
        "cost_per_conv_p90_usd":  1.20,
        "llm_cost_ratio_p50":     0.35,
        "gross_margin_p50_pct":   38.0,
        "resolution_rate_p50":    0.55,
    },
}

def benchmark_position(
    feature_type: str,
    cost_per_conv: float,
    gross_margin_pct: float,
) -> dict:
    bm = INDUSTRY_BENCHMARKS.get(feature_type)
    if not bm:
        return {"error": f"No benchmark for {feature_type!r}"}
    p50 = bm["cost_per_conv_p50_usd"]
    p90 = bm["cost_per_conv_p90_usd"]
    percentile = (
        "top-quartile"  if cost_per_conv < p50 * 0.75 else
        "median"        if cost_per_conv < p50 * 1.25 else
        "below-median"  if cost_per_conv < p90 else
        "bottom-decile"
    )
    return {
        "feature_type": feature_type,
        "your_cost_per_conv": cost_per_conv,
        "industry_p50": p50,
        "industry_p90": p90,
        "percentile_band": percentile,
        "margin_vs_p50": gross_margin_pct - bm["gross_margin_p50_pct"],
    }
